func NewTLS2RawPlugin(options v1.ClientPluginOptions) (Plugin, error) {
	opts := options.(*v1.TLS2RawPluginOptions)

	p := &TLS2RawPlugin{
		opts: opts,
	}

	tlsConfig, err := transport.NewServerTLSConfig(p.opts.CrtPath, p.opts.KeyPath, "")
	if err != nil {
		return nil, err
	}
	p.tlsConfig = tlsConfig
	return p, nil
}
